-- ─── 1. Actualité : lancement public Bayen (le plus récent) ────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'bayen-est-en-ligne',
  'Bayen est en ligne : scanner, comprendre, choisir',
  'Après des mois de préparation, l''application marocaine de notation des produits alimentaires est ouverte à tous. Gratuite, open source, sans pub.',
  E'## Un outil pour reprendre le contrôle\n\nAu Maroc, les rayons débordent de produits importés, de promesses marketing, d''emballages rassurants. Entre le "bio", le "sans sucre ajouté" et le "riche en fibres", il devient impossible de distinguer les bons produits des mauvais sans lire dix étiquettes à chaque course.\n\n**Bayen** ("c''est clair, ça se voit" en darija) répond à ce besoin : scanne un code-barres, obtiens un score de 0 à 100 calculé de façon transparente, et comprends en 3 secondes ce que tu achètes vraiment.\n\n## Ce qu''on t''apporte dès maintenant\n\n- **Plus de 25 000 produits** disponibles dès le lancement (importés d''Open Food Facts + contributions communauté marocaine)\n- **Score Bayen** objectif : Nutri-Score officiel + groupe NOVA + additifs détectés\n- **Détection des additifs** interdits ou à éviter au Maroc\n- **100% gratuit**, sans publicité, sans tracking invasif\n- **Open source** : [le code est public sur GitHub](https://github.com/Santofer/bayen)\n\n## Comment tu peux aider\n\nLa base grandit chaque jour avec vos scans. Si un produit est absent, tu peux l''ajouter en 1 minute depuis l''app :\n\n1. Scanne le code-barres\n2. Prends une photo du tableau nutritionnel\n3. L''OCR rempli les champs automatiquement\n\n> Le Maroc a besoin d''une base nutritionnelle indépendante. Chaque produit que tu ajoutes bénéficie à tous.\n\n[Scanne ton premier produit](/scan) ou [explore la base](/recherche).',
  'actualites',
  2,
  'published',
  NOW() - INTERVAL '6 hours'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 2. Guide : comprendre le Nutri-Score ──────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'comprendre-le-nutri-score',
  'Le Nutri-Score expliqué simplement (et ses limites)',
  'A, B, C, D, E : tu vois ces lettres partout mais tu n''es pas sûr de ce qu''elles veulent dire. On démêle tout en 4 minutes.',
  E'## D''où vient le Nutri-Score\n\nLe Nutri-Score est un système de notation nutritionnelle créé en France en 2017, aujourd''hui adopté par 7 pays européens. Il résume la qualité nutritionnelle d''un produit en une seule lettre : **A** (vert foncé, le meilleur) à **E** (rouge, le moins bon).\n\nIl est calculé par un algorithme public qui regarde 100g du produit et compte :\n\n### Les points "défavorables" (ce qu''on veut moins)\n- énergie (kcal)\n- sucres\n- acides gras saturés\n- sodium (sel)\n\n### Les points "favorables" (ce qu''on veut plus)\n- fibres\n- protéines\n- fruits, légumes, légumineuses\n\nLa différence donne une note, qui se traduit en lettre.\n\n## Pourquoi c''est utile\n\n**C''est instantané**. Tu n''as pas besoin de comparer 8 chiffres sur deux étiquettes. Un regard sur la lettre, tu sais.\n\n**C''est standardisé**. Tous les produits du même type sont notés avec le même barème, donc la comparaison est juste.\n\n**Ça te pousse à mieux** : en 2024, plusieurs industriels ont reformulé leurs recettes pour passer d''un D à un C.\n\n## Ses 4 limites importantes\n\n1. **Il ignore les additifs**. Un soda "sans sucre" peut gagner un B grâce aux édulcorants — alors qu''il contient de l''aspartame ou de l''acésulfame-K. C''est pour ça que **Bayen déduit des points sur les additifs à risque**, en plus du Nutri-Score.\n\n2. **Il ignore la transformation**. Une céréale ultra-transformée riche en fibres peut avoir un Nutri-Score A. C''est pour ça qu''on regarde aussi le **groupe NOVA**.\n\n3. **Il ignore l''origine et le bio**. Un biscuit industriel importé et un artisanal local peuvent avoir la même note.\n\n4. **Il ne fait pas la distinction portions/format**. 100g de chips et 100g de pain complet sont comparés avec le même barème, alors que tu ne les consommes pas en même quantité.\n\n## Notre conseil\n\nUtilise le Nutri-Score comme **un premier filtre**, pas comme l''unique critère. Sur Bayen, on le combine avec NOVA et les additifs pour obtenir un score plus complet.\n\n> Un produit Nutri-Score A n''est pas forcément "bon" — c''est juste "moins pire nutritionnellement que ses voisins de rayon".\n\nÀ lire ensuite : [le groupe NOVA expliqué](/blog/pourquoi-eviter-ultra-transforme).',
  'guides',
  4,
  'published',
  NOW() - INTERVAL '1 day'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 3. Guide : additifs à éviter ──────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'additifs-a-eviter-maroc',
  'Les 8 additifs à vraiment éviter dans les rayons marocains',
  'Tous les additifs ne se valent pas. Voici les plus problématiques qu''on trouve encore fréquemment dans les supermarchés au Maroc.',
  E'## Pourquoi certains additifs sont problématiques\n\nLes additifs alimentaires (les fameux "E-xxx") sont des substances ajoutées aux produits pour améliorer leur conservation, leur texture, leur couleur ou leur goût. **La plupart sont sans danger** aux doses alimentaires normales.\n\nMais certains sont **contestés** par les autorités sanitaires (EFSA, ANSES, OMS) à cause d''études associant leur consommation régulière à des effets néfastes : perturbation du microbiote, inflammation, suspicion cancérigène, hyperactivité chez les enfants.\n\nVoici la liste à retenir.\n\n## 1. E102 — Tartrazine (colorant jaune)\n\nColorant azoïque jaune. Suspecté de provoquer de l''hyperactivité chez les enfants. Obligation d''étiquetage renforcée en Europe. On le trouve dans **certains bonbons, sirops et biscuits importés**.\n\n## 2. E129 — Rouge Allura AC\n\nColorant azoïque rouge. Controverse similaire au E102. Interdit au Danemark, Belgique, France pendant des années. Présent dans **sodas rouges, bonbons, glaces colorées**.\n\n## 3. E951 — Aspartame\n\nÉdulcorant artificiel. **Classé "possiblement cancérigène" par l''OMS en juillet 2023** (catégorie 2B). On le trouve dans presque tous les **sodas light/zero** et produits "sans sucre".\n\n## 4. E621 — Glutamate monosodique (GMS)\n\nExhausteur de goût. Responsable chez certaines personnes du "syndrome du restaurant chinois" (maux de tête, palpitations). À limiter. Très présent dans **soupes instantanées, cubes bouillon, chips, plats préparés**.\n\n## 5. E220 à E228 — Sulfites\n\nConservateurs. Allergènes reconnus, obligation d''étiquetage si >10 mg/kg. Peuvent déclencher des crises d''asthme. Dans les **vins, fruits secs, crustacés, produits à base de pommes de terre**.\n\n## 6. E320 (BHA) et E321 (BHT)\n\nAntioxydants synthétiques. Le BHA est **classé "possiblement cancérigène" par le CIRC**. Présents dans **certaines céréales industrielles, gommes à mâcher, charcuteries**.\n\n## 7. E249 et E250 — Nitrite de sodium/potassium\n\nConservateurs des charcuteries. Transformés en nitrosamines dans l''organisme, **classées cancérigènes par le CIRC**. L''OMS recommande de limiter drastiquement les charcuteries.\n\n## 8. E171 — Dioxyde de titane\n\nColorant blanc / opacifiant. **Interdit en Europe depuis 2022** car ses effets génotoxiques ne sont plus écartables. Encore présent dans certains **produits importés** (chewing-gums, bonbons, pâtisseries industrielles) sur les rayons marocains.\n\n## Comment les éviter facilement\n\nSur **Bayen**, chaque produit scanné affiche ses additifs avec un code couleur :\n\n- 🟢 vert : sans risque aux doses habituelles\n- 🟠 orange : à limiter\n- 🔴 rouge : à éviter\n- ⚫ noir : interdit au Maroc ou en UE\n\nTu peux aussi [parcourir notre base d''additifs](/additifs) pour comprendre chaque E-xxx.\n\n> Chaque additif pris isolément représente peu de risque. C''est l''accumulation dans l''alimentation quotidienne qui devient problématique.',
  'guides',
  5,
  'published',
  NOW() - INTERVAL '2 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 4. Guide : lire une étiquette ─────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'lire-une-etiquette-nutritionnelle',
  'Lire une étiquette en 60 secondes : la méthode qui change tout',
  'Tableau nutritionnel, liste des ingrédients, allégations marketing : on te donne la grille de lecture que les industriels détestent.',
  E'## L''ordre de lecture qui compte\n\nLa plupart des gens regardent l''avant du paquet (le marketing) et ignorent le dos (la vérité). Pour lire une étiquette comme un pro, **inverse cet ordre**.\n\n### Étape 1 — La liste des ingrédients (5 secondes)\n\nRègle d''or : **les ingrédients sont classés par ordre décroissant de quantité**. Le premier est le plus présent.\n\n- Si **sucre**, **sirop de glucose**, **huile de palme** ou **farine raffinée** est dans les 3 premiers → alerte.\n- Si la liste dépasse **5 ingrédients inconnus ou chimiques** → c''est ultra-transformé.\n- Si tu vois **plusieurs noms pour le sucre** (sucre, sirop de glucose-fructose, dextrose, maltose, concentré de jus...) → on essaie de te le cacher. La somme de tous ces sucres dépasse souvent 30%.\n\n### Étape 2 — Le tableau nutritionnel (15 secondes)\n\nRegarde les valeurs **pour 100g** (pas "par portion" — souvent biaisé). Les seuils à retenir :\n\n| Nutriment | Faible | Élevé |\n|---|---|---|\n| Sucres | < 5g | > 15g |\n| Matières grasses saturées | < 1.5g | > 5g |\n| Sel | < 0.3g | > 1.5g |\n| Fibres | > 6g (bon) | — |\n\n**Exemples chocs** :\n- Un Coca classique : 10.6g de sucre / 100g → élevé\n- Des céréales "chocolat" enfants : 20–30g de sucre / 100g → très élevé\n- Des chips : 1.5g de sel / 100g → limite haute\n\n### Étape 3 — Les allégations marketing (10 secondes à ignorer)\n\n"**Riche en calcium**" — peut venir d''ajouts artificiels plutôt que d''un produit naturellement riche.\n\n"**Allégé**" / "**light**" — au moins 30% de moins qu''une référence, mais "moins" ne veut pas dire "peu".\n\n"**Sans sucre ajouté**" — ne veut pas dire "sans sucre". Il y a peut-être 25% de sucre naturel.\n\n"**Naturel**" — aucune définition légale. Ne signifie rien.\n\n"**Bio**" — certifie l''absence de pesticides et d''OGM, mais **ne dit rien sur la qualité nutritionnelle**. Un biscuit bio peut être aussi sucré qu''un non-bio.\n\n### Étape 4 — Les additifs (10 secondes)\n\nCherche les "**E-xxx**". S''il y en a :\n\n- **0 à 2** : normal\n- **3 à 5** : produit transformé, regarde lesquels\n- **6+** : ultra-transformé, à limiter\n\n## Pourquoi Bayen fait ça pour toi\n\nToute cette analyse, on la fait **en 3 secondes** pour chaque produit que tu scannes. Tu gagnes 60 secondes par produit, 30 minutes par session de courses.\n\n> La lecture d''étiquette n''est pas un super-pouvoir. C''est juste une habitude, comme regarder le prix avant de payer.\n\n[Commence par scanner ce que tu as déjà dans tes placards](/scan) — tu vas avoir des surprises.',
  'guides',
  4,
  'published',
  NOW() - INTERVAL '3 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 5. Bien-être : sucre caché ────────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'sucre-cache-produits-marocains',
  'Le sucre caché dans 7 produits que tu achètes chaque semaine',
  'Un yaourt "nature", une sauce tomate, des céréales "équilibrées"… combien de morceaux de sucre contient vraiment ton petit-déj ?',
  E'## L''OMS le dit : pas plus de 25 g de sucres ajoutés / jour\n\nL''Organisation mondiale de la santé recommande de ne pas dépasser **6 cuillères à café de sucres ajoutés** par jour (25 g). Pourtant, un Marocain moyen en consomme **plus du double**, souvent sans s''en rendre compte.\n\nLa raison : le sucre est caché dans des produits qu''on ne soupçonne pas. Voici 7 exemples concrets (avec équivalent en morceaux de sucre, 1 morceau = 4 g).\n\n## 1. Yaourt aromatisé "fraise" — 13 g / 125 g\n\n**= 3 morceaux de sucre**. Même en version "allégée en matières grasses", un yaourt fraise contient plus de sucre qu''un carré de chocolat noir 70%.\n\n**Alternative** : yaourt nature + morceaux de vraie fraise + 1 c. à café de miel. Tu divises le sucre par 2.\n\n## 2. Céréales "chocapic", "coco pops" etc. — 30 g / 100 g\n\n**= 7 morceaux par bol d''enfant (100g)**. Les céréales "équilibrées" pour enfants sont souvent composées à 30% de sucre, parfois plus. Leur Nutri-Score est généralement D ou E.\n\n**Alternative** : flocons d''avoine nature + cannelle + banane écrasée. 0 g de sucre ajouté.\n\n## 3. Jus de fruits "100% pur jus" — 10 g / 100 ml\n\n**= 10 morceaux dans un grand verre (400ml)**. Même "sans sucre ajouté", un jus contient tous les sucres du fruit **sans les fibres** qui en ralentissent l''absorption. L''effet sur la glycémie est proche de celui d''un soda.\n\n**Alternative** : eau infusée avec tranches d''orange + menthe. Ou mange le fruit entier.\n\n## 4. Ketchup — 22 g / 100 g\n\n**= 1.5 morceau par cuillère à soupe**. Le ketchup contient plus de sucre que de tomate. Les versions "bio" ou "artisanales" sont souvent aussi sucrées.\n\n**Alternative** : sauce tomate maison (concentré + oignon + herbes). 0 g de sucre ajouté.\n\n## 5. Sauce "barbecue" / "chinoise" / "samouraï" — 30–45 g / 100 g\n\n**= 2 à 3 morceaux par c. à soupe**. Les sauces préparées sont des bombes de sucre. La "sauce soja sucrée" peut monter à 50% de sucre.\n\n## 6. Boissons "à base de jus" (cocktails, tea, etc.) — 8–12 g / 100 ml\n\n**= 8 à 12 morceaux par canette de 330 ml**. Ice Tea, Oasis, Orangina, limonades artisanales : la majorité contiennent autant de sucre qu''un Coca.\n\n## 7. Barres de céréales "énergie" — 25 g / 50 g\n\n**= 3 morceaux par barre**. Commercialisées pour les sportifs ou les enfants, ces barres sont essentiellement du sucre compressé avec 10% de flocons d''avoine.\n\n## Le réflexe à prendre\n\n**Scanne chaque produit avant d''acheter**. Sur Bayen, la valeur "sucres pour 100g" est toujours affichée, et le score pénalise automatiquement les produits au-dessus de 15g/100g.\n\n> Reduire le sucre ne veut pas dire arrêter. C''est juste remplacer les sources invisibles (celles qui te droguent sans plaisir) par les sources visibles (le dessert que tu choisis et que tu savoures).\n\nÀ essayer ce week-end : [scanne ton placard et fais ton top 5](/scan) des aliments les plus sucrés. Tu seras surpris.',
  'bien-etre',
  5,
  'published',
  NOW() - INTERVAL '4 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 6. Bien-être : éviter ultra-transformé ────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'pourquoi-eviter-ultra-transforme',
  'NOVA 4 : pourquoi limiter les aliments ultra-transformés change tout',
  'Un seul critère, validé par la recherche, prédit mieux la qualité d''un produit que tous les Nutri-Score réunis. Voici comment l''appliquer.',
  E'## Qu''est-ce que la classification NOVA\n\nNOVA est un système de classification créé en 2009 par des chercheurs brésiliens (Pr. Carlos Monteiro, université de São Paulo). Il range les aliments en **4 groupes** selon leur niveau de transformation :\n\n### NOVA 1 — Aliments non transformés ou peu transformés\nFruits, légumes, légumineuses, céréales brutes, viandes fraîches, lait, œufs, poisson, épices. Juste nettoyés, séchés, broyés, fermentés.\n\n### NOVA 2 — Ingrédients culinaires\nHuile, sel, sucre, beurre, farine. Extraits de NOVA 1 et utilisés pour cuisiner NOVA 1.\n\n### NOVA 3 — Aliments transformés\nCombinaison de NOVA 1 et NOVA 2 avec des procédés classiques (pain, fromage, conserves de légumes, viandes fumées, poisson en boîte…). Reconnaissable : **liste d''ingrédients courte** (3-5 ingrédients), tout ce que tu pourrais avoir dans ta cuisine.\n\n### NOVA 4 — Aliments ultra-transformés\nProduits industriels avec **additifs cosmétiques** (colorants, arômes, exhausteurs, émulsifiants) et/ou **ingrédients d''extraction industrielle** (maltodextrine, protéines isolées, sirop de glucose-fructose, amidon modifié…). Exemples : sodas, céréales petit-déj, plats préparés, nuggets, biscuits fourrés, charcuteries industrielles, glaces industrielles, boissons "à base de".\n\n## Pourquoi c''est le critère le plus important\n\nDes dizaines d''études ont comparé la consommation d''ultra-transformés à diverses maladies chroniques. Les résultats sont **massifs et convergents** :\n\n- **+62%** de risque de mortalité toutes causes pour les grands consommateurs (étude NutriNet-Santé, 2019, 45 000 participants)\n- **+31%** de risque de diabète type 2 pour chaque augmentation de 10% d''ultra-transformés dans le régime\n- **+53%** de risque de dépression (méta-analyse 2023)\n- **+12%** de risque de cancer pour chaque augmentation de 10%\n\n**Ce que ça veut dire concrètement** : un produit NOVA 4 avec un Nutri-Score B est généralement **pire pour la santé long-terme** qu''un produit NOVA 3 avec un Nutri-Score C. Le système NOVA prédit mieux les résultats santé que tout autre critère nutritionnel isolé.\n\n## Les 3 signaux qui trahissent un NOVA 4\n\n1. **La liste d''ingrédients dépasse 5 éléments** dont au moins 1 que tu ne reconnais pas\n2. Tu vois des termes comme : *maltodextrine, sirop de glucose-fructose, amidon modifié, émulsifiant, exhausteur, arôme, stabilisant, colorant, lécithine de soja*\n3. Le produit **ne ressemble pas à sa matière première** (les nuggets de poulet ne ressemblent plus au poulet)\n\n## Le défi simple : **80/20**\n\nNe cherche pas la perfection. Vise **80% NOVA 1-3** dans ta semaine, laisse-toi **20% de NOVA 4** pour les occasions / les moments de plaisir.\n\nDe petits changements accessibles :\n\n- Céréales petit-déj → flocons d''avoine nature\n- Jambon industriel → œuf, poulet rôti maison, sardines\n- Jus "100% pur jus" → fruit entier\n- Barre "énergie" → poignée d''amandes\n- Yaourt sucré aromatisé → yaourt nature + miel\n\n## Comment Bayen t''aide\n\nLe score Bayen intègre le groupe NOVA dans son calcul. Scanne un produit : si NOVA 4, l''app le signale clairement et pénalise le score final, même si le Nutri-Score est bon.\n\n> On n''est pas fanatiques. On consomme tous des produits ultra-transformés. La différence, c''est d''en être conscient et d''en choisir moins.\n\nÀ lire ensuite : [comment lire une étiquette en 60s](/blog/lire-une-etiquette-nutritionnelle).',
  'bien-etre',
  6,
  'published',
  NOW() - INTERVAL '5 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 7. Bien-être : enfants et nutrition ───────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'parler-nutrition-enfants',
  'Parler nutrition à ses enfants sans les braquer',
  'Interdire ne marche pas. Culpabiliser encore moins. Voici 5 approches qui installent durablement les bonnes habitudes chez les enfants.',
  E'## L''interdiction crée l''envie\n\nTous les parents l''ont constaté : **l''aliment interdit devient l''aliment désiré**. Les enfants privés de sucre à la maison se gavent chez les copains. Les adolescents cachent les biscuits dans leur chambre.\n\nLes recherches en psychologie du comportement alimentaire le confirment : la restriction autoritaire augmente la consommation du produit "interdit" à l''adolescence. Ce qui marche, c''est **l''éducation par la curiosité et le choix éclairé**.\n\n## 1. Transforme l''étiquette en jeu\n\nÀ partir de 6 ans, les enfants adorent chercher des chiffres. Donne-leur une mission : "Trouve combien de morceaux de sucre il y a dans ton jus préféré." Utilise la règle simple : **chaque 4g de sucre = 1 morceau**.\n\nMatérialise-le : prends un morceau de sucre pour chaque tranche de 4g. Pour un Coca de 33cl (35g de sucre) → 9 morceaux visibles dans un bol. L''effet visuel est spectaculaire.\n\n## 2. Laisse-les scanner (ils adorent ça)\n\nLes enfants raffolent de scanner. Sur **Bayen**, l''app affiche un score de 0 à 100 + une couleur. **Fais-en une routine** : au supermarché, chaque enfant a son rôle de "scanner officiel".\n\n"*Ce biscuit, il est vert ou rouge ?*" est une question 100 fois plus engageante que "*c''est bon ou mauvais ?*"\n\n## 3. Explique au lieu d''interdire\n\nAu lieu de : "Non, pas de soda."\n\nEssaie : "Le soda, c''est chouette pour les moments de fête. Pour tous les jours, c''est trop sucré pour ton corps. Tu préfères de l''eau aromatisée maison ou du jus de fruit frais ?"\n\nLa clé : **donner le choix entre deux options acceptables**. L''enfant sent qu''il contrôle, tu gardes le cadre.\n\n## 4. Implique-les dans les courses et la cuisine\n\nUn enfant qui a choisi ses légumes au souk les mange plus volontiers. Un enfant qui a cuisiné le pain au thym ne le laisse pas dans l''assiette.\n\n**Objectif simple** : 1 fois par semaine, l''enfant choisit l''un des repas de la semaine (avec ton arbitrage). 1 fois par semaine, il met la main à la pâte.\n\n## 5. Fais-toi l''exemple\n\nLes enfants copient. Si tu bois un soda à chaque repas, expliquer que "le soda c''est pour les fêtes" ne marchera pas. L''exemple parental est **le facteur n°1** de formation des habitudes alimentaires à vie.\n\n> Ton enfant ne retiendra pas ce que tu lui as dit sur la nutrition. Il retiendra ce que tu lui as montré pendant 18 ans.\n\n## Les pièges à éviter absolument\n\n- ❌ **Utiliser la nourriture comme récompense** ("Si tu es sage, tu auras un bonbon")\n- ❌ **Utiliser la nourriture comme punition** ("Tu ne sortiras pas de table tant que...")\n- ❌ **Commenter le corps des enfants** (risque de troubles du comportement alimentaire à l''adolescence)\n- ❌ **Interdire complètement un aliment** (effet rebond garanti)\n\n## Le petit rituel qui marche\n\nUne fois par mois, fais un "inventaire du placard" en famille. Scanne chaque produit ensemble. Ceux qui sont rouges, tu en discutes : "*On les garde pour les occasions, ou on trouve mieux ?*"\n\nEn 6 mois, la composition du placard change **naturellement**, sans drame, sans conflit.\n\n[Commence dès maintenant avec ton enfant](/scan).',
  'bien-etre',
  5,
  'published',
  NOW() - INTERVAL '6 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 8. Habitudes : alternatives saines snacks ─────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'alternatives-snacks-industriels',
  '10 alternatives saines aux snacks industriels (à moins de 5 DH)',
  'Remplacer les biscuits fourrés et chips sans exploser le budget : la liste pratique des alternatives marocaines.',
  E'## Pourquoi c''est accessible au Maroc\n\nOn entend souvent : "*Manger sainement, c''est cher.*" C''est **faux** — si tu remplaces les snacks industriels par des aliments bruts, tu économises souvent de l''argent.\n\nVoici 10 alternatives testées, réalistes, et moins chères que leur équivalent industriel.\n\n## 1. Biscuits fourrés → **Dattes Medjoul**\n\n- **Biscuit industriel** : 15 DH / paquet, ~30g de sucre / 100g, NOVA 4, 7 additifs\n- **Dattes Medjoul** : 30-40 DH / kg (soit ~1.5 DH la datte), zéro additif, fibres + potassium\n\n**Verdict** : 2 dattes = énergie équivalente à 3 biscuits, avec bien plus de nutriments. Tu trouves des Medjoul dans toutes les épiceries de quartier.\n\n## 2. Chips → **Pois chiches grillés aux épices**\n\nAchète des pois chiches secs (10 DH / kg), trempe une nuit, fais-les griller 30 min au four avec un filet d''huile d''olive et du paprika/cumin.\n\n**Résultat** : croquant, protéiné, conserve 2 semaines dans un bocal. **Coût** : ~5 DH pour 500 g = l''équivalent de 5 paquets de chips.\n\n## 3. Biscuits secs → **Amandes & noix**\n\n- **Amandes** : 100 DH / kg (cher, mais 20 amandes = une portion)\n- **Cacahuètes nature** (pas salées, pas grillées aux huiles) : 25 DH / kg\n\n**Astuce** : achète-les non salées au souk pour contrôler le sel.\n\n## 4. Bonbons → **Fruits secs sans sucre ajouté**\n\nAbricots secs, raisins secs, figues sèches. **Attention** : lis l''étiquette. Certains fruits secs industriels ont du sucre ajouté ou des sulfites (E220). Cherche ceux qui affichent seulement le fruit dans la liste d''ingrédients.\n\n## 5. Yaourt aromatisé → **Yaourt nature + fruit + miel**\n\n- 1 yaourt nature (2 DH) + 1 c. à c. de miel (1 DH) + 1/2 banane ou 3 fraises (1 DH) = **4 DH**\n- Un yaourt aromatisé industriel = 4-5 DH, **3× plus de sucre**, arômes artificiels.\n\n## 6. Céréales du petit-déj → **Flocons d''avoine**\n\nFlocons d''avoine : 15 DH / 500g (vs 40 DH / 500g pour des Chocapic). Ajoute cannelle, morceaux de pomme, miel selon goût.\n\n**Bonus santé** : -40% de sucre, +300% de fibres, indice glycémique bien plus bas (tu tiens jusqu''à midi sans faim).\n\n## 7. Jus en brique → **Citronnade maison**\n\n1 citron pressé + 400 ml d''eau + 1 c. à c. de miel (optionnel) = 1 pichet pour **toute la famille à 2-3 DH**.\n\nVs 1 brique de jus à 8-15 DH.\n\n## 8. Barres chocolatées → **Carré de chocolat noir 70%**\n\nLe chocolat noir >70% contient **moins de sucre et plus de flavonoïdes** que le chocolat au lait. 2 carrés suffisent pour satisfaire une envie.\n\n**Marque repère** : cherche les tablettes avec **moins de 5 ingrédients** dans la liste.\n\n## 9. Nuggets industriels → **Blanc de poulet pané maison**\n\n- Coupe un blanc de poulet en lanières, trempe dans œuf, roule dans de la chapelure + cumin, cuis au four 20 min.\n- **20-25 DH pour 4 personnes** vs 50 DH pour des nuggets industriels.\n\n## 10. Sauces industrielles → **Yaourt + citron + herbes**\n\nMayonnaise, ketchup, sauce cocktail → remplace par 3 c. à s. de yaourt grec + 1 c. à c. de citron + menthe ciselée + sel, poivre. **1 DH par portion**, zéro additif.\n\n## Le défi des 10 jours\n\nPendant 10 jours, remplace **UN seul snack** industriel par son alternative. Juste un. La différence est assez spectaculaire pour te convaincre d''en remplacer un deuxième le mois suivant.\n\n> On ne change pas tout d''un coup. On remplace un produit à la fois. En 6 mois, ton placard est transformé.\n\n[Scanne ton snack préféré et compare son score Bayen](/scan).',
  'habitudes',
  5,
  'published',
  NOW() - INTERVAL '7 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 9. Habitudes : courses en 3 min ───────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'courses-methode-3-minutes',
  'Ma méthode "3 minutes" pour des courses qui ne plombent pas la santé',
  'Pas envie de transformer chaque course en marathon ? Voici la routine simple et répétable qui installe durablement le réflexe Bayen.',
  E'## Le mythe du "je cuisine tout maison"\n\nOn nous vend souvent un idéal inatteignable : cuisiner tout soi-même, tout bio, tout frais. **C''est irréaliste** pour 95% des familles qui travaillent.\n\nLa vraie question n''est pas "comment cuisiner tout", c''est **"comment acheter le mieux possible en 45 minutes hebdomadaires"**. Voici la méthode.\n\n## Avant de partir : 90 secondes\n\n1. **Écris ta liste** — 10 produits max, ceux que tu achètes chaque semaine. Sans liste, tu sors avec 40% de produits en plus.\n2. **Ne pars jamais le ventre vide** — tu achètes 2× plus de sucré quand tu as faim. Avis confirmé par 6 études en neurosciences.\n3. **Prévois 45 min** — trop court → tu stresses et tu craques. Trop long → tu remplis le chariot.\n\n## Au rayon : 3 minutes par produit INCONNU\n\n**Règle clé** : **les produits que tu achètes déjà ne demandent rien**. Tu n''as pas besoin de re-vérifier ton pain habituel, ton huile d''olive habituelle, ton yaourt nature. Applique les 3 minutes **uniquement aux nouveautés** (30-40% de ton chariot, pas plus).\n\nPour chaque nouveau produit :\n\n### Minute 1 — Scan\nScan le code-barres avec Bayen. Tu as le score immédiat.\n\n- **80-100** (vert foncé) : excellent, prends.\n- **60-80** (vert clair) : bon, prends.\n- **40-60** (orange) : moyen, regarde la concurrence.\n- **< 40** (rouge) : cherche mieux, même rayon.\n\n### Minute 2 — Compare avec un concurrent direct\nSi le score est orange ou rouge, scanne 1 ou 2 voisins dans le rayon. Souvent, un produit à 200 mètres plus loin fait 20 points de plus pour 1 DH de plus.\n\n### Minute 3 — Décide et note\nPrends ta décision. **Si tu achètes, garde le produit dans tes favoris** pour la prochaine fois (tu ne referas pas le scan).\n\n## Après les courses : 60 secondes\n\nDe retour chez toi, prends 60 secondes pour noter mentalement (ou dans un carnet) **3 produits** que tu as aimés et **3 produits** que tu regrettes (score trop bas).\n\nEn 4 semaines, tu as une liste mentale claire des "toujours bons" et des "jamais plus". Tu ne refais plus les analyses.\n\n## Le gain de temps réel\n\n| Phase | Première course avec Bayen | Après 4 semaines |\n|---|---|---|\n| Temps au rayon | 45 min | 35 min |\n| Produits nouveaux à scanner | 15 | 3-5 |\n| Analyse par produit | 2-3 min | 30 s |\n\n**En quelques semaines, tu deviens plus rapide qu''avant**, parce que tes achats récurrents sont identifiés comme "déjà validés".\n\n## Le piège à éviter : l''excès de perfectionnisme\n\nNe scanne pas **tous les produits à chaque course**. Le cerveau sature et tu abandonnes après 3 semaines.\n\n**Principe du 80/20** : scanne juste les produits qui représentent la majorité de ton budget santé (céréales, biscuits, sauces, charcuteries, snacks). Laisse tranquilles les produits bruts (fruits, légumes, viandes fraîches, poisson) — ils n''ont même pas de code-barres.\n\n> La meilleure méthode de courses saines est celle que tu continues à appliquer dans 6 mois. Pas celle qui te semble parfaite aujourd''hui.\n\n## À essayer samedi\n\n1. Prépare ta liste (10 produits)\n2. Prends ton téléphone avec Bayen ouvert\n3. Scanne les 5 premières nouveautés\n4. Note les 3 meilleurs scores\n\nTu l''auras en habitude au bout de 3 courses.\n\n[Commence ta liste maintenant avec l''app](/recherche).',
  'habitudes',
  4,
  'published',
  NOW() - INTERVAL '8 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 10. Habitudes : habitudes ramadan ─────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'bien-manger-ramadan',
  'Ramadan : 5 règles pour un ftour qui nourrit vraiment',
  'Dattes, chebbakia, harira, jus : comment composer un ftour qui te soutient jusqu''au s''hor, sans crash glycémique 1h après.',
  E'## Pourquoi le ftour typique fatigue plus qu''il ne nourrit\n\nLe ftour marocain traditionnel est riche, social, rituel. Mais certains de ses composants — en grande quantité quotidienne — créent des **pics glycémiques** qui te laissent fatigué 1 heure après.\n\nLe trio problématique : **jus sucrés industriels + chebbakia/pâtisseries sucrées + peu de protéines**. Tu finis par avoir faim à 23h et grignoter jusqu''au s''hor.\n\nVoici 5 règles pratiques pour un ftour plus nourrissant, sans renier la tradition.\n\n## 1. Commence par les dattes + eau (pas les boissons sucrées)\n\nLa tradition prophétique est claire : dattes + eau à la rupture du jeûne. **C''est nutritionnellement brillant** :\n\n- Les dattes apportent du sucre naturel accompagné de fibres (contrairement aux sodas/jus) → glycémie douce\n- L''eau réhydrate sans charge calorique\n- Le minéral potassium des dattes compense la perte de la journée\n\n**Évite** : les boissons industrielles (Rani, Pulpy, Jaïda en brique), même "naturelles". Elles contiennent 10g de sucre / 100 ml sans les fibres des fruits entiers.\n\n## 2. La harira : une mine d''or, si elle est faite maison\n\nLa harira traditionnelle est **un repas complet** : protéines (pois chiches, lentilles, viande), fibres (tomates, céleri, persil), glucides complexes. **Garde-la.**\n\n**Attention aux versions** : harira en sachet, cubes "harira" industriels — additifs, GMS (E621), sel très élevé. Scanne-les sur Bayen si tu veux vérifier.\n\n## 3. Limite les chebbakia à 2 pièces\n\nLa chebbakia est un concentré de sucre + huile + miel. **Une seule chebbakia de taille moyenne contient 80-100 kcal et 15g de sucre**. Trois chebbakia = l''équivalent sucré d''une canette de Coca.\n\nSolution : 2 pièces max, savourées lentement, en fin de ftour (pas comme démarreur).\n\n## 4. Ajoute une vraie source de protéines\n\nLe ftour classique (dattes + jus + harira + chebbakia + pain) manque souvent de protéines solides. Résultat : tu as faim 2h après.\n\nAjoute **au moins un des éléments** :\n\n- 2 œufs durs ou en omelette\n- Sardines grillées\n- Blanc de poulet grillé\n- Fromage frais (100g)\n\nLa satiété remonte de 3 à 5 heures. Tu dors mieux, tu grignotes moins.\n\n## 5. Le s''hor qui évite la soif de journée\n\nAu s''hor (repas avant l''aube), évite **le sel, les épices fortes, et les sucres rapides**. Ils te donneront soif dès 10h.\n\nFormule recommandée :\n- **Glucides complexes** : pain complet, flocons d''avoine, couscous\n- **Protéines** : œufs, yaourt nature, fromage\n- **Bonnes graisses** : huile d''olive, amandes\n- **Hydratation** : 2 grands verres d''eau (pas de thé sucré — diurétique)\n\nExemple : bol d''avoine + lait + dattes + amandes + 2 verres d''eau. Tiens jusqu''au ftour sans soif.\n\n## Le piège marketing spécial Ramadan\n\nLes supermarchés lancent des **offres "spéciales Ramadan"** sur des produits ultra-transformés : gâteaux industriels, boissons aux fruits en promo, pâtes à tartiner économiques. Ce sont les mêmes NOVA 4 que le reste de l''année, avec une étiquette lune.\n\n**Scan Bayen avant de remplir ton chariot.** Les scores ne changent pas pendant Ramadan.\n\n> Un Ramadan réussi nutritionnellement, c''est un mois où tu te sens plus léger, pas plus lourd. Ça passe par la composition de l''assiette, pas par la privation.\n\nCheck ton prochain ftour : [scanne les produits industriels que tu penses acheter](/scan) et regarde leur score avant.',
  'habitudes',
  5,
  'published',
  NOW() - INTERVAL '9 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

COMMIT;

-- Vérification finale
SELECT slug, category, reading_time_min, status,
       to_char(date_published, 'YYYY-MM-DD HH24:MI') AS published_at,
       length(content_fr) AS content_chars
FROM articles
ORDER BY date_published DESC;
